#!/usr/bin/env python3
"""apply_sengekokujo_art.py — inject updated Sengekokujo portraits (a970-a984)
into assets/assets.json. Idempotent; run from repo root. Box art a985 is left
untouched. Regenerated 2026-07-15 with de-texted, re-cropped portraits."""
import json, os, sys
root=os.path.dirname(os.path.abspath(__file__))
ap=os.path.join(root,"assets/assets.json")
if not os.path.exists(ap): sys.exit("[apply] assets/assets.json not found — run from repo root")
assets=json.load(open(ap))
ART={
  "a970": "data:image/jpeg;base64,",
  "a971": "data:image/jpeg;base64,",
  "a972": "data:image/jpeg;base64,",
  "a973": "data:image/jpeg;base64,",
  "a974": "data:image/jpeg;base64,",
  "a975": "data:image/jpeg;base64,",
  "a976": "data:image/jpeg;base64,",
  "a977": "data:image/jpeg;base64,",
  "a978": "data:image/jpeg;base64,",
  "a979": "data:image/jpeg;base64,",
  "a980": "data:image/jpeg;base64,",
  "a981": "data:image/jpeg;base64,",
  "a982": "data:image/jpeg;base64,",
  "a983": "data:image/jpeg;base64,",
  "a984": "data:image/jpeg;base64,",
}
for k,v in ART.items(): assets[k]=v
json.dump(assets, open(ap,"w"))
print(f"[apply] wrote {len(ART)} Sengekokujo portraits (a970-a984) into assets.json")
